package com.school.config;
import com.school.entity.*; import com.school.enums.RoleName; import com.school.repository.*; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.*; import org.springframework.security.crypto.password.PasswordEncoder;
@Configuration public class DataInitializer { @Bean CommandLineRunner initialData(UserRepository users,FacultyRepository faculties,AnnouncementRepository announcements,PasswordEncoder passwords){return args->{if(users.count()>0)return; users.save(new User("admin","admin@campus.edu",passwords.encode("Admin@123"),"System Administrator",RoleName.ADMIN));users.save(new User("lecturer","lecturer@campus.edu",passwords.encode("Lecturer@123"),"Dr. Grace Wanjiku",RoleName.LECTURER));users.save(new User("student","student@campus.edu",passwords.encode("Student@123"),"Alex Mwangi",RoleName.STUDENT));faculties.save(new Faculty("Faculty of Computing"));announcements.save(new Announcement("Welcome to Campus Portal","The new semester is now open. Check your timetable and complete unit registration."));};} }
